import fs from "node:fs";
import path from "node:path";
import { createRequire } from "node:module";
import { spawnSync } from "node:child_process";

const ROOT_DIR = path.resolve(import.meta.dirname, "..");
const OUTPUT_DIR = path.join(ROOT_DIR, "src-tauri", "gen", "licenses-bundle");
const FRONTEND_MANIFEST_PATH = path.join(ROOT_DIR, "package.json");
const FRONTEND_LOCK_PATH = path.join(ROOT_DIR, "bun.lock");
const RUST_MANIFEST_PATH = path.join(ROOT_DIR, "src-tauri", "Cargo.toml");
const RUST_LOCK_PATH = path.join(ROOT_DIR, "src-tauri", "Cargo.lock");
const THIRD_PARTY_SOURCE_DIR = path.join(ROOT_DIR, "third_party", "redistributables");
const THIRD_PARTY_SPDX_DIR = path.join(ROOT_DIR, "third_party", "spdx");
const STANDARD_LICENSE_FILES = {
  "Apache-2.0": path.join(THIRD_PARTY_SPDX_DIR, "Apache-2.0.txt"),
  "BSD-3-Clause": path.join(THIRD_PARTY_SPDX_DIR, "BSD-3-Clause.txt"),
  MIT: path.join(THIRD_PARTY_SPDX_DIR, "MIT.txt"),
  "MPL-2.0": path.join(THIRD_PARTY_SPDX_DIR, "MPL-2.0.txt"),
};

const BUNDLED_BINARIES = [
  {
    kind: "redistributable-binary",
    name: "ONNX Runtime",
    version: "1.23.0",
    sourceDir: path.join(THIRD_PARTY_SOURCE_DIR, "onnxruntime-1.23.0"),
    distributedFiles: [
      "onnxruntime.dll",
      "onnxruntime_providers_shared.dll",
    ],
  },
  {
    kind: "redistributable-binary",
    name: "DirectML",
    version: "1.15.4",
    sourceDir: path.join(THIRD_PARTY_SOURCE_DIR, "directml-1.15.4"),
    distributedFiles: ["DirectML.dll"],
  },
];

const BUNDLED_NPM_PACKAGES = [
  {
    name: "@agentmemory/agentmemory",
    version: "0.9.24",
    bundleDir: path.join(ROOT_DIR, "src-tauri", "gen", "agentmemory-bundle"),
  },
];

main();

function main() {
  resetDirectory(OUTPUT_DIR);

  const frontend = generateFrontendBundle();
  const rust = generateRustBundle();
  const binaries = generateBinaryBundle();
  const agentmemory = generateAgentmemoryBundle();
  const manifests = copyManifestInputs();

  writeText(
    path.join(OUTPUT_DIR, "README.md"),
    `# Third-Party License Bundle

This directory is generated by \`scripts/generate-third-party-bundle.mjs\` before \`bun tauri build\`.

It collects:
- frontend runtime dependency license texts and notices under \`frontend/packages/\`
- Rust runtime crate license texts and notices under \`rust/crates/\`
- fallback SPDX license texts for registry packages that ship only license expressions and omit text files
- installer input manifests and lockfiles under \`manifests/\`
- third-party license and notice texts for redistributed binary/runtime components under \`binaries/\`

Unity Editor DLL bundle notices remain bundled with \`locus_unity/Editor/Roslyn\` and \`locus_unity/Editor/Json\` and are not duplicated here.
`
  );

  writeJson(path.join(OUTPUT_DIR, "bundle-manifest.json"), {
    frontend,
    rust,
    binaries,
    agentmemory,
    manifests,
  });
}

function generateFrontendBundle() {
  const packageJson = readJson(FRONTEND_MANIFEST_PATH);
  const packagesDir = path.join(OUTPUT_DIR, "frontend", "packages");
  ensureDirectory(packagesDir);

  const seen = new Set();
  const records = [];

  for (const dependencyName of Object.keys(packageJson.dependencies || {}).sort()) {
    walkFrontendDependency(dependencyName, ROOT_DIR, seen, records, packagesDir);
  }

  records.sort(comparePackageRecords);
  writeJson(path.join(OUTPUT_DIR, "frontend", "index.json"), {
    runtimeRoots: Object.keys(packageJson.dependencies || {}).sort(),
    packageCount: records.length,
    packages: records,
  });

  return {
    packageCount: records.length,
    runtimeRoots: Object.keys(packageJson.dependencies || {}).sort(),
  };
}

function walkFrontendDependency(dependencyName, fromDirectory, seen, records, packagesDir) {
  const requireFrom = createRequire(path.join(fromDirectory, "package.json"));
  let manifestPath;
  try {
    manifestPath = requireFrom.resolve(`${dependencyName}/package.json`);
  } catch {
    return;
  }

  if (seen.has(manifestPath)) {
    return;
  }
  seen.add(manifestPath);

  const manifest = readJson(manifestPath);
  const manifestDirectory = path.dirname(manifestPath);
  const outputDirectory = path.join(packagesDir, packageFolderName(manifest.name, manifest.version));
  ensureDirectory(outputDirectory);

  const legalFiles = collectLegalFiles(manifestDirectory);
  const copiedFiles =
    legalFiles.length > 0
      ? copyLegalFiles(legalFiles, manifestDirectory, outputDirectory)
      : writeFallbackLicenseFiles(outputDirectory, manifest.license, `${manifest.name}@${manifest.version}`);

  records.push({
    name: manifest.name,
    version: manifest.version,
    license: manifest.license ?? null,
    packageJsonPath: toRepoRelative(manifestPath),
    texts: copiedFiles.map(toOutputRelative),
  });

  const nextDependencies = new Set([
    ...Object.keys(manifest.dependencies || {}),
    ...Object.keys(manifest.optionalDependencies || {}),
  ]);

  for (const nextDependency of [...nextDependencies].sort()) {
    walkFrontendDependency(nextDependency, manifestDirectory, seen, records, packagesDir);
  }
}

function generateRustBundle() {
  const metadata = loadCargoMetadata();
  const packagesDir = path.join(OUTPUT_DIR, "rust", "crates");
  ensureDirectory(packagesDir);

  const rootPackage = metadata.packages.find(
    (pkg) => normalizePath(pkg.manifest_path) === normalizePath(RUST_MANIFEST_PATH)
  );
  if (!rootPackage) {
    throw new Error(`Unable to find root package for ${RUST_MANIFEST_PATH}`);
  }

  const nodeById = new Map(metadata.resolve.nodes.map((node) => [node.id, node]));
  const packageById = new Map(metadata.packages.map((pkg) => [pkg.id, pkg]));
  const runtimePackageIds = new Set();

  walkRustDependencies(rootPackage.id, nodeById, runtimePackageIds);

  const records = [];
  for (const packageId of [...runtimePackageIds].sort()) {
    const pkg = packageById.get(packageId);
    if (!pkg || !pkg.source) {
      continue;
    }

    const manifestDirectory = path.dirname(pkg.manifest_path);
    const outputDirectory = path.join(packagesDir, packageFolderName(pkg.name, pkg.version));
    ensureDirectory(outputDirectory);

    const legalFiles = collectLegalFiles(manifestDirectory);
    const copiedFiles =
      legalFiles.length > 0
        ? copyLegalFiles(legalFiles, manifestDirectory, outputDirectory)
        : writeFallbackLicenseFiles(outputDirectory, pkg.license, `${pkg.name}@${pkg.version}`);

    records.push({
      name: pkg.name,
      version: pkg.version,
      source: pkg.source,
      license: pkg.license ?? null,
      texts: copiedFiles.map(toOutputRelative),
    });
  }

  records.sort(comparePackageRecords);
  writeJson(path.join(OUTPUT_DIR, "rust", "index.json"), {
    packageCount: records.length,
    packages: records,
  });

  return {
    packageCount: records.length,
  };
}

function walkRustDependencies(packageId, nodeById, runtimePackageIds) {
  if (runtimePackageIds.has(packageId)) {
    return;
  }
  runtimePackageIds.add(packageId);

  const node = nodeById.get(packageId);
  if (!node) {
    return;
  }

  for (const dependency of node.deps || []) {
    if (dependency.dep_kinds?.some((kind) => kind.kind === null)) {
      walkRustDependencies(dependency.pkg, nodeById, runtimePackageIds);
    }
  }
}

function generateBinaryBundle() {
  const records = [];
  for (const binary of BUNDLED_BINARIES) {
    if (!fs.existsSync(binary.sourceDir)) {
      throw new Error(`Missing third-party source directory: ${binary.sourceDir}`);
    }

    const outputDirectory = path.join(
      OUTPUT_DIR,
      "binaries",
      packageFolderName(binary.name.toLowerCase().replace(/\s+/g, "-"), binary.version)
    );
    ensureDirectory(outputDirectory);

    const legalFiles = collectLegalFiles(binary.sourceDir);
    if (legalFiles.length === 0) {
      throw new Error(`No third-party notice or license files found in ${binary.sourceDir}`);
    }

    const copiedFiles = copyLegalFiles(legalFiles, binary.sourceDir, outputDirectory);
    records.push({
      kind: binary.kind,
      name: binary.name,
      version: binary.version,
      sourceDir: toRepoRelative(binary.sourceDir),
      distributedFiles: binary.distributedFiles,
      texts: copiedFiles.map(toOutputRelative),
    });
  }

  records.sort(comparePackageRecords);
  writeJson(path.join(OUTPUT_DIR, "binaries", "index.json"), {
    packageCount: records.length,
    packages: records,
  });

  return {
    packageCount: records.length,
  };
}

function generateAgentmemoryBundle() {
  const packagesDir = path.join(OUTPUT_DIR, "agentmemory", "packages");
  ensureDirectory(packagesDir);
  const records = [];

  for (const pkg of BUNDLED_NPM_PACKAGES) {
    const segments = pkg.name.startsWith("@") ? pkg.name.slice(1).split("/") : [pkg.name];
    const packageRoot = path.join(pkg.bundleDir, "node_modules", ...segments);
    const outputDirectory = path.join(packagesDir, packageFolderName(pkg.name, pkg.version));
    ensureDirectory(outputDirectory);

    if (!fs.existsSync(packageRoot)) {
      writeText(
        path.join(outputDirectory, "NOTICE.txt"),
        `${pkg.name}@${pkg.version}\n\nBundle not built yet. Run \`bun run agentmemory:bundle\` before release builds.\n`,
      );
      records.push({
        kind: "bundled-npm-package",
        name: pkg.name,
        version: pkg.version,
        status: "missing-bundle",
        texts: [toOutputRelative(path.join(outputDirectory, "NOTICE.txt"))],
      });
      continue;
    }

    const legalFiles = collectLegalFiles(packageRoot);
    const copiedFiles =
      legalFiles.length > 0
        ? copyLegalFiles(legalFiles, packageRoot, outputDirectory)
        : [
            writeTextReturnPath(
              path.join(outputDirectory, "NOTICE.txt"),
              `${pkg.name}@${pkg.version}\n\nNo LICENSE file found in bundled package directory.\n`,
            ),
          ];

    writeText(
      path.join(outputDirectory, "III-NOTICE.txt"),
      "iii-engine v0.11.2 is bundled separately under agentmemory-bundle/bin/ from https://github.com/iii-hq/iii\n",
    );
    copiedFiles.push(path.join(outputDirectory, "III-NOTICE.txt"));

    records.push({
      kind: "bundled-npm-package",
      name: pkg.name,
      version: pkg.version,
      status: "present",
      sourceDir: toRepoRelative(packageRoot),
      texts: copiedFiles.map(toOutputRelative),
    });
  }

  records.sort(comparePackageRecords);
  writeJson(path.join(OUTPUT_DIR, "agentmemory", "index.json"), {
    packageCount: records.length,
    packages: records,
  });

  return {
    packageCount: records.length,
  };
}

function writeTextReturnPath(filePath, contents) {
  writeText(filePath, contents);
  return filePath;
}

function copyManifestInputs() {
  const manifestCopies = [
    {
      source: FRONTEND_MANIFEST_PATH,
      destination: path.join(OUTPUT_DIR, "manifests", "frontend", "package.json"),
    },
    {
      source: FRONTEND_LOCK_PATH,
      destination: path.join(OUTPUT_DIR, "manifests", "frontend", "bun.lock"),
    },
    {
      source: RUST_MANIFEST_PATH,
      destination: path.join(OUTPUT_DIR, "manifests", "rust", "Cargo.toml"),
    },
    {
      source: RUST_LOCK_PATH,
      destination: path.join(OUTPUT_DIR, "manifests", "rust", "Cargo.lock"),
    },
  ];

  for (const entry of manifestCopies) {
    ensureDirectory(path.dirname(entry.destination));
    fs.copyFileSync(entry.source, entry.destination);
  }

  writeJson(path.join(OUTPUT_DIR, "manifests", "index.json"), {
    files: manifestCopies.map((entry) => ({
      source: toRepoRelative(entry.source),
      bundlePath: toOutputRelative(entry.destination),
    })),
  });

  return {
    fileCount: manifestCopies.length,
  };
}

function loadCargoMetadata() {
  const result = spawnSync(
    "cargo",
    [
      "metadata",
      "--format-version",
      "1",
      "--manifest-path",
      RUST_MANIFEST_PATH,
      "--filter-platform",
      "x86_64-pc-windows-msvc",
    ],
    {
      cwd: ROOT_DIR,
      encoding: "utf8",
      maxBuffer: 1024 * 1024 * 64,
    }
  );

  if (result.status !== 0) {
    throw new Error(result.stderr || result.stdout || "cargo metadata failed");
  }

  return JSON.parse(result.stdout);
}

function collectLegalFiles(directory) {
  return fs
    .readdirSync(directory, { withFileTypes: true })
    .filter((entry) => entry.isFile() && isLegalFileName(entry.name))
    .map((entry) => entry.name)
    .sort((left, right) => left.localeCompare(right));
}

function isLegalFileName(fileName) {
  const normalized = fileName.toLowerCase();
  return (
    normalized.startsWith("license") ||
    normalized.startsWith("licence") ||
    normalized.startsWith("notice") ||
    normalized.startsWith("notices") ||
    normalized.startsWith("thirdpartynotices") ||
    normalized.startsWith("third-party-notices") ||
    normalized.startsWith("copying")
  );
}

function copyLegalFiles(fileNames, sourceDirectory, destinationDirectory) {
  const copiedFiles = [];
  for (const fileName of fileNames) {
    const source = path.join(sourceDirectory, fileName);
    const destination = path.join(destinationDirectory, fileName);
    fs.copyFileSync(source, destination);
    copiedFiles.push(destination);
  }
  return copiedFiles;
}

function writeFallbackLicenseFiles(destinationDirectory, licenseExpression, subject) {
  const licenseIds = extractFallbackLicenseIds(licenseExpression);
  if (licenseIds.length === 0) {
    throw new Error(`Unable to derive fallback license texts for ${subject}: ${licenseExpression ?? "(missing license expression)"}`);
  }

  const copiedFiles = [];
  for (const licenseId of licenseIds) {
    const sourceFile = STANDARD_LICENSE_FILES[licenseId];
    if (!sourceFile || !fs.existsSync(sourceFile)) {
      throw new Error(`Missing bundled fallback text for ${licenseId} (${subject})`);
    }
    const destination = path.join(destinationDirectory, `LICENSE-${licenseId}.txt`);
    fs.copyFileSync(sourceFile, destination);
    copiedFiles.push(destination);
  }
  return copiedFiles;
}

function extractFallbackLicenseIds(licenseExpression) {
  if (!licenseExpression) {
    return [];
  }

  const matched = licenseExpression.match(/[A-Za-z0-9.+-]+/g) || [];
  const filtered = matched.filter(
    (token) => !["AND", "OR", "WITH"].includes(token.toUpperCase()) && token !== "LLVM-exception"
  );

  return [...new Set(filtered.filter((token) => token in STANDARD_LICENSE_FILES))].sort((left, right) =>
    left.localeCompare(right)
  );
}

function packageFolderName(name, version) {
  return `${sanitizeSegment(name)}-${sanitizeSegment(version)}`;
}

function sanitizeSegment(value) {
  return value.replace(/^@/, "at-").replace(/[<>:"/\\|?*\x00-\x1F]+/g, "_");
}

function comparePackageRecords(left, right) {
  return `${left.name}@${left.version}`.localeCompare(`${right.name}@${right.version}`);
}

function resetDirectory(directory) {
  fs.rmSync(directory, { recursive: true, force: true });
  fs.mkdirSync(directory, { recursive: true });
}

function ensureDirectory(directory) {
  fs.mkdirSync(directory, { recursive: true });
}

function writeJson(filePath, value) {
  writeText(filePath, `${JSON.stringify(value, null, 2)}\n`);
}

function writeText(filePath, value) {
  ensureDirectory(path.dirname(filePath));
  fs.writeFileSync(filePath, value, "utf8");
}

function readJson(filePath) {
  return JSON.parse(fs.readFileSync(filePath, "utf8"));
}

function normalizePath(filePath) {
  return filePath.replace(/\\/g, "/");
}

function toOutputRelative(filePath) {
  return normalizePath(path.relative(OUTPUT_DIR, filePath));
}

function toRepoRelative(filePath) {
  return normalizePath(path.relative(ROOT_DIR, filePath));
}
